                dataStore.computeIfAbsent(entityType, k -> Collections.synchronizedList(new ArrayList<>()));
                dataStore.get(entityType).addAll(records);
                totalImported += records.size();
                batchCount++;
                summary.append(String.format("Batch[%s]: %d records for %s; ",
                        batchId != null ? batchId : String.valueOf(batchCount),
                        records.size(), entityType));
