    private List<Map<String, String>> parseRecords(Node recordsNode) {
        List<Map<String, String>> records = new ArrayList<>();
        NodeList recordNodes = recordsNode.getChildNodes();

        for (int i = 0; i < recordNodes.getLength(); i++) {
            Node recordNode = recordNodes.item(i);
            if (recordNode.getNodeType() != Node.ELEMENT_NODE) {
                continue;
            }

            Map<String, String> record = new LinkedHashMap<>();

            // Parse attributes
            NamedNodeMap attributes = recordNode.getAttributes();
            if (attributes != null) {
                for (int j = 0; j < attributes.getLength(); j++) {
                    Node attr = attributes.item(j);
                    record.put("@" + attr.getNodeName(), attr.getNodeValue());
                }
            }

            // Parse child elements
            NodeList fields = recordNode.getChildNodes();
            for (int j = 0; j < fields.getLength(); j++) {
                Node field = fields.item(j);
                if (field.getNodeType() == Node.ELEMENT_NODE) {
                    String fieldName = field.getLocalName() != null ? field.getLocalName() : field.getNodeName();
                    String fieldValue = field.getTextContent();
                    record.put(fieldName, fieldValue != null ? fieldValue.trim() : "");
                }
            }

            if (!record.isEmpty()) {
                records.add(record);
            }
        }

        return records;
    }

    private Map<String, String> parseFilters(Node filtersNode) {
        Map<String, String> filters = new LinkedHashMap<>();
        NodeList filterNodes = filtersNode.getChildNodes();

        for (int i = 0; i < filterNodes.getLength(); i++) {
            Node filterNode = filterNodes.item(i);
            if (filterNode.getNodeType() == Node.ELEMENT_NODE && "Filter".equals(filterNode.getLocalName())) {
                String field = getChildElementText(filterNode, "Field");
                String value = getChildElementText(filterNode, "Value");
                if (field != null && value != null) {
                    filters.put(field, value);
                }
            }
        }

        return filters;
    }

    private List<Map<String, String>> applyFilters(List<Map<String, String>> records, Map<String, String> filters) {
        List<Map<String, String>> result = new ArrayList<>();
        for (Map<String, String> record : records) {
            boolean matches = true;
            for (Map.Entry<String, String> filter : filters.entrySet()) {
                String recordValue = record.get(filter.getKey());
                if (recordValue == null || !recordValue.equalsIgnoreCase(filter.getValue())) {
                    matches = false;
                    break;
                }
            }
            if (matches) {
                result.add(record);
            }
        }
        return result;
    }

